/// Physical memory end (PA) as discovered from the device tree.  It is set
/// during `init_frame_allocator` and may be read with `phys_memory_end()`.
static PHYS_MEMORY_END: AtomicUsize = AtomicUsize::new(Constant::MEMORY_END);

/// Return the physical end address of RAM discovered from the device tree.
/// Falls back to `Constant::MEMORY_END` before the frame allocator is
/// initialized.
pub fn phys_memory_end() -> usize {
    PHYS_MEMORY_END.load(Ordering::Relaxed)
}

/// Discover the end of physical RAM from the built-in DTB.
///
/// QEMU may pass any amount of RAM (e.g. 1 GiB on the scoring platform), while
/// the kernel constants still describe the original 8 GiB layout.  Using the
/// real limit prevents the frame allocator from handing out physical frames
/// that are not actually backed by memory.
unsafe fn detect_phys_memory_end() -> usize {
    let dtb_addr = hal::board::get_device_tree_addr();
    let fdt = match fdt::Fdt::from_ptr(dtb_addr as *const u8) {
        Ok(f) => f,
        Err(_) => return Constant::MEMORY_END,
    };
    let mut end = 0usize;
    for region in fdt.memory().regions() {
        let start = region.starting_address as usize;
        let size = region.size.unwrap_or(0);
        if size == 0 {
            continue;
        }
        let region_end = match start.checked_add(size) {
            Some(e) => e,
            None => continue,
        };
        if region_end > start && region_end > end {
            end = region_end;
        }
    }
    if end == 0 {
        Constant::MEMORY_END
    } else {
        end.min(Constant::MEMORY_END)
    }
}

/// Global flag used to avoid recursive dirty-page writeback while the frame
/// allocator is already performing dirty writeback.  Recursion can happen
/// because flushing a dirty page performs block I/O, and the DMA path may
/// itself need to allocate frames.
static DIRTY_WRITEBACK_IN_PROGRESS: AtomicBool = AtomicBool::new(false);


/// Try to satisfy a frame allocation request by evicting clean page-cache pages
/// when the ordinary allocator is exhausted.
fn alloc_with_aggressive_reclaim<F>(size: usize, mut try_alloc: F) -> Option<Range<PhysPageNum>>
where
    F: FnMut() -> Option<Range<PhysPageNum>>,
{
    // Reclaim in a few rounds; each round tries to free at least `size` pages.
    for round in 0..4 {
        if let Some(range) = try_alloc() {
            return Some(range);
        }
        let evicted = crate::fs::page::cache::evict_global_clean_pages(size);
        if evicted > 0 {
            println!(
                "[FrameAllocator] reclaim round {}: evicted {} clean pages for request {}",
                round, evicted, size
            );
        }
        if evicted == 0 {
            // No clean pages left. Flush a batch of dirty page-cache pages and evict them.
            // Avoid recursive dirty writeback: if we are already flushing dirty pages
            // deeper in the call stack, skip the dirty step this time.
            if DIRTY_WRITEBACK_IN_PROGRESS
                .compare_exchange(false, true, Ordering::Acquire, Ordering::Relaxed)
                .is_ok()
            {
                struct DirtyWritebackGuard;
                impl Drop for DirtyWritebackGuard {
                    fn drop(&mut self) {
                        DIRTY_WRITEBACK_IN_PROGRESS.store(false, Ordering::Release);
                    }
                }
                let _guard = DirtyWritebackGuard;
                let dirty_target = core::cmp::max(size, 512);
                let dirty_evicted = crate::fs::page::cache::evict_global_dirty_pages(dirty_target);
                if dirty_evicted > 0 {
                    println!(
                        "[FrameAllocator] reclaim round {}: flushed {} dirty pages for request {}",
                        round, dirty_evicted, size
                    );
                    // The flushed pages are now clean; try clean eviction again next round.
                    continue;
                }
            }
            break;
        }
    }
    if let Some(range) = try_alloc() {
        return Some(range);
    }
    let free_pages = FRAME_ALLOCATOR.lock().last;
    println!(
        "[FrameAllocator] allocation failed for {} pages, free pages: {}",
        size, free_pages
    );
    None
}
use core::fmt::{self, Debug, Formatter};
