            ret.insert(MmapFlags::MAP_SHARED);
        } else {
            ret.insert(MmapFlags::MAP_PRIVATE);
        }
        if !self.file.is_file() {
            ret.insert(MmapFlags::MAP_ANONYMOUS);
        }
        ret
    }
