bitflags! {
    /// Defined in <bits/sched.h>
    pub struct CloneFlags: u64 {
        /// Set if VM shared between processes.
        const VM = 0x0000100;
        /// Set if fs info shared between processes.
        const FS = 0x0000200;
        /// Set if open files shared between processes.
        const FILES = 0x0000400;
        /// Set if signal handlers shared.
        const SIGHAND = 0x00000800;
        /// Set if a pidfd should be placed in parent.
        const PIDFD = 0x00001000;
        /// Set if we want to have the same parent as the cloner.
        const PARENT = 0x00008000;
        /// Set to add to same thread group.
        const THREAD = 0x00010000;
        /// Set to shared SVID SEM_UNDO semantics.
        const SYSVSEM = 0x00040000;
        /// Set TLS info.
        const SETTLS = 0x00080000;
        /// Store TID in userlevel buffer before MM copy.
        const PARENT_SETTID = 0x00100000;
        /// Register exit futex and memory location to clear.
        const CHILD_CLEARTID = 0x00200000;
        /// Store TID in userlevel buffer in the child.
        const CHILD_SETTID = 0x01000000;
        /// Create clone detached.
        const DETACHED = 0x00400000;
        /// Set if the tracing process can't
        const UNTRACED = 0x00800000;
        /// New cgroup namespace.
        const NEWCGROUP = 0x02000000;
        /// New utsname group.
        const NEWUTS = 0x04000000;
        /// New ipcs.
        const NEWIPC = 0x08000000;
        /// New user namespace.
        const NEWUSER = 0x10000000;
        /// New pid namespace.
        const NEWPID = 0x20000000;
        /// New network namespace.
        const NEWNET = 0x40000000;
        /// Clone I/O context.
        const IO = 0x80000000 ;
        /// CLone_legacy_flag
        const LEGACY_FLAGS = 0xffffffff ;
    }
}

bitflags! {
    /// Defined in <bits/waitflags.h>.
    pub struct WaitOptions: i32 {
        /// Don't block waiting.
        const WNOHANG = 0x00000001;
        /// Report status of stopped children.
        const WUNTRACED = 0x00000002;
        /// Report continued child.
        const WCONTINUED = 0x00000008;
    }
}

/// get the pid of the current process
pub fn sys_getpid() -> SysResult {
    // log::info!("[sys_getpid]: in get pid");
    Ok(current_task().unwrap().pid() as isize)
}
/// get the tid of the current thread
pub fn sys_gettid() -> SysResult {
    Ok(current_task().unwrap().tid() as isize)
}

pub fn sys_setuid(uid: i32) -> SysResult {
    let task = current_task().unwrap().clone();
    log::warn!("task {} set its uid to {}", task.tid(), uid);
    task.set_euid(uid);
    task.set_suid(uid);
    task.set_ruid(uid);
    Ok(0)
}

pub fn sys_setgid(gid: i32) -> SysResult {
    let task = current_task().unwrap().clone();
    task.set_rgid(gid);
    task.set_egid(gid);
    task.set_sgid(gid);
    Ok(0)
}

pub fn sys_setresgid(rgid: i32, egid: i32, sgid: i32) -> SysResult {
    let task = current_task().unwrap().clone();
    if rgid != -1 {
        task.set_rgid(rgid);
    }
    if egid != -1 {
        task.set_egid(egid);
    }
    if sgid != -1 {
        task.set_sgid(sgid);
    }
    Ok(0)
}

pub fn sys_setregid(rgid: i32, egid: i32) -> SysResult {
    let task = current_task().unwrap().clone();
    let old_rgid = task.rgid();
    let old_egid = task.egid();
    if rgid != -1 {
        task.set_rgid(rgid);
    }
    if egid != -1 {
        task.set_egid(egid);
    }
    if rgid != -1 || (egid != -1 && egid != old_rgid) {
        if egid == -1 {
            task.set_sgid(old_egid);
        } else {
            task.set_sgid(egid);
        }
    }
    Ok(0)
}


pub fn sys_setresuid(ruid: i32, euid: i32, suid: i32) -> SysResult {
    let task = current_task().unwrap().clone();
    if ruid != -1 {
        task.set_ruid(ruid);
    }
    if euid != -1 {
        task.set_euid(euid);
    }
    if suid != -1 {
        task.set_suid(suid);
    }
    Ok(0)
}

pub fn sys_setreuid(ruid: i32, euid: i32) -> SysResult {
    let task = current_task().unwrap().clone();
    let old_ruid = task.ruid();
    let old_euid = task.euid();
    if ruid != -1 {
        task.set_ruid(ruid);
    }
    if euid != -1 {
        task.set_euid(euid);
    }
    if ruid != -1 || (euid != -1 && euid != old_ruid) {
        if euid == -1 {
            task.set_suid(old_euid);
        } else {
            task.set_suid(euid);
        }
    }
    Ok(0)
}

