impl TryFrom<u16> for SaFamily {
    type Error = crate::syscall::sys_error::SysError;
    fn try_from(value: u16) -> Result<Self,Self::Error> {
        match Self::from_repr(value){
            Some(family) => Ok(family),
            None => Err(SysError::EINVAL ),
        }
    }
}

