fn get_device_name(device_kind: BlockDeviceKind ,i: isize) -> String {
    if device_kind == BlockDeviceKind::Nvme{
        return "nvme".to_string() + &i.to_string();
    }
    let a = i / 26;
    let b = i % 26;
    let mut last = alphabet[b as usize].to_string();
    let mut first = "".to_string();
    if a > 0 {
        first = alphabet[a as usize].to_string();
    }
    let mut num = first + last.as_str();
    if device_kind == BlockDeviceKind::Ide{
        return "hd".to_string() + num.as_str();
    }
    else{
        return "sd".to_string() + num.as_str();
    }
}

