/// mount point for disk fs
static DISK_MP: &str = "/";
/// device name for disk fs
static DISK_DNAME: &str = "ext4_fs0";
/// mount point for sdcard fs
static SDCARD_MP: &str = "sdcard/";
/// device name for sdcard fs
static SDCARD_DNAME: &str = "ext4_fs1";

impl FSType for Ext4FSType {
    fn inner(&self) -> &FSTypeInner {
        &self.inner
    }
    fn kill_sb(&self) -> isize {
        todo!()
    }
    fn mount(&'static self, name: &str, parent: Option<Arc<dyn Dentry>>, _flags: MountFlags, dev: Option<Arc<dyn BlockDevice>>) -> Option<Arc<dyn Dentry>> {
        // can be dangerous..
        let fs_type = unsafe {
            let ptr: *const dyn FSType = self;
            Arc::from_raw(ptr)
        };

        let (mount_point_path, dev_name): (&'static str, &'static str) = if parent.is_none() {
            (DISK_MP, DISK_DNAME)
        } else {
            let parent_path = parent.as_ref().unwrap().path();
            let mut path = alloc::format!("{}/{}", parent_path.trim_end_matches('/'), name);
            if !path.ends_with('/') {
                path.push('/');
            }
            let path: &'static str = Box::leak(path.into_boxed_str());
            let dev_name = alloc::format!("ext4_fs_{}", name);
            let dev_name: &'static str = Box::leak(dev_name.into_boxed_str());
            (path, dev_name)
        };

        log::info!(
            "[ext4 mount] name={}, mount_point={}, dev_name={}",
            name, mount_point_path, dev_name
        );

        let sb = match Ext4SuperBlock::new(SuperBlockInner::new(dev, fs_type.clone()), mount_point_path, dev_name){
            Ok(sb) => sb,
            Err(e) => {
                log::warn!("[ext4 mount] failed to create superblock: {}", e);
                return None;
            }
        };
        let root_inode = Ext4Inode::new(Arc::downgrade(&sb), mount_point_path, InodeTypes::EXT4_DE_DIR);
        let root_dentry = Ext4Dentry::new(name, parent.clone());
        root_dentry.set_inode(root_inode);
        root_dentry.set_state(DentryState::USED);
        sb.set_root_dentry(root_dentry.clone());
        DCACHE.lock().insert(mount_point_path.to_string(), root_dentry.clone());
        self.add_sb(&root_dentry.path(), sb);
        Some(root_dentry)
    }
}

