//! Page Cache
//! each inode will hold a page cache
//! (todos): 1. radix tree to manage the offset to page
//! 2. ahead read 

use core::{cmp, sync::atomic::{AtomicUsize, Ordering}};

use crate::{fs::vfs::Inode, sync::mutex::SpinNoIrqLock};
use alloc::{collections::btree_map::BTreeMap, sync::{Arc, Weak}, vec::Vec};
// use hashbrown::HashMap;
use log::info;

use super::page::{Page, PAGE_SIZE};

/// Global registry of all page caches, used to reclaim memory under pressure.
static PAGE_CACHES: SpinNoIrqLock<Vec<Weak<PageCache>>> = SpinNoIrqLock::new(Vec::new());

/// Register a page cache so it can be reclaimed globally.
pub fn register_page_cache(cache: &Arc<PageCache>) {
    PAGE_CACHES.lock().push(Arc::downgrade(cache));
}

/// Evict clean pages from all registered page caches until at least
/// `target_pages` pages have been freed.  Returns the number of pages evicted.
pub fn evict_global_clean_pages(target_pages: usize) -> usize {
    let mut total = 0;
    let caches: Vec<Arc<PageCache>> = {
        let caches = PAGE_CACHES.lock();
        caches.iter().filter_map(|weak| weak.upgrade()).collect()
    };
    for cache in caches {
        if total >= target_pages {
            break;
        }
        total += cache.evict_all_clean_pages();
    }
    total
}

/// Write back up to `target_pages` dirty pages from all registered caches,
/// then evict the now-clean pages so their frames are freed.
/// Returns the number of frames freed.
pub fn evict_global_dirty_pages(target_pages: usize) -> usize {
    let caches: Vec<Arc<PageCache>> = {
        let caches = PAGE_CACHES.lock();
        caches.iter().filter_map(|weak| weak.upgrade()).collect()
    };
    let mut written = 0;
    for cache in caches {
        if written >= target_pages {
            break;
        }
        written += cache.writeback_dirty_pages(target_pages - written);
    }
    if written > 0 {
        evict_global_clean_pages(written)
    } else {
        0
    }
}

/// Maximum number of cached pages per inode.
/// This bounds the amount of physical memory a single file cache can consume.
const MAX_CACHED_PAGES_PER_INODE: usize = 256;

pub struct PageCache {
    /// from file offset(should be page aligned)
    /// to the cached page
    /// TODO: now use BTreeMap to flush data from low off to high off
    /// to avoid the 'Seek Beyond file size' problem
    /// should fs support this?
    pages: SpinNoIrqLock<BTreeMap<usize, Arc<Page>>>,
    /// the postion of EOF
    /// save it to prevent endless read
    /// notice that it may need to update when 
    /// cache write, as it may lead to expand the file
    end: AtomicUsize,
    /// Back-pointer to the owning inode, used to write back dirty pages
    /// when the frame allocator is under memory pressure.
    inode: SpinNoIrqLock<Option<Weak<dyn Inode>>>,
}

impl PageCache {
    /// create a new Page Cache
    pub fn new() -> Self {
        Self {
            pages: SpinNoIrqLock::new(BTreeMap::new()),
            end: AtomicUsize::new(0usize),
            inode: SpinNoIrqLock::new(None),
        }
    }

    /// Create a new Page Cache wrapped in an Arc and register it for global reclaim.
    pub fn new_arc() -> Arc<Self> {
        let cache = Arc::new(Self::new());
        register_page_cache(&cache);
        cache
    }

    /// Associate this page cache with its owning inode.
    pub fn set_inode(&self, inode: Weak<dyn Inode>) {
        *self.inode.lock() = Some(inode);
    }

    /// Write back up to `limit` dirty pages and mark them clean.
    /// Returns the number of pages successfully written back.
    pub fn writeback_dirty_pages(&self, limit: usize) -> usize {
        let dirty: Vec<(usize, Arc<Page>)> = {
